export function resolveFamily({
	family,
	hasher,
}: {
	family: FontFamily;
	hasher: Hasher;
}): ResolvedFontFamily {
	// We remove quotes from the name so they can be properly resolved by providers.
	const name = withoutQuotes(family.name);

	return {
		...family,
		name,
		// This will be used in CSS font faces. Quotes are added by the CSS renderer if
		// this value contains a space.
		uniqueName: `${name}-${hasher.hashObject(family)}`,
		weights: family.weights ? dedupe(family.weights.map((weight) => weight.toString())) : undefined,
		styles: family.styles ? dedupe(family.styles) : undefined,
		subsets: family.subsets ? dedupe(family.subsets) : undefined,
		formats: family.formats ? dedupe(family.formats) : undefined,
		fallbacks: family.fallbacks ? dedupe(family.fallbacks) : undefined,
		unicodeRange: family.unicodeRange ? dedupe(family.unicodeRange) : undefined,
	};
}

resolve(id: string): string {
	const prefix = this.#assetsPrefix
		? getAssetsPrefix(fileExtension(id), this.#assetsPrefix)
		: undefined;
	let urlPath: string;
	if (prefix) {
		this.#resources.add(prefix);
		urlPath = joinPaths(prefix, this.#base, id);
	} else {
		this.#resources.add("'self'");
		urlPath = prependForwardSlash(joinPaths(this.#base, id));
	}

	// Create URL object and append searchParams if available (for adapter-level tracking like skew protection)
	const url = createPlaceholderURL(urlPath);
	this.#searchParams.forEach((value, key) => {
		url.searchParams.set(key, value);
	});

	const result = stringifyPlaceholderURL(url);
	this.#urls.add(result);
	return result;
}

async function handleSvgDeduplication(
	fileData: Buffer,
	filename: string,
	fileEmitter: FileEmitter,
): Promise<string> {
	const contentHash = await generateContentHash(fileData.buffer as ArrayBuffer);
	const key = keyFor(contentHash);
	const existing = svgContentCache.get(key);

	if (existing) {
		// Emit file again with the same filename to get a new handle
		// This ensures Rollup knows about this handle while maintaining deduplication on disk
		const handle = fileEmitter({
			name: existing.filename,
			source: fileData,
			type: 'asset',
		});
		return handle;
	} else {
		// First time seeing this SVG content - emit it
		const handle = fileEmitter({
			name: filename,
			source: fileData,
			type: 'asset',
		});
		svgContentCache.set(key, { handle, filename });
		return handle;
	}
}

async #getLoaderContext({
	collectionName,
	loaderName = 'content',
	parseData,
	refreshContextData,
}: {
	collectionName: string;
	loaderName: string;
	parseData: LoaderContext['parseData'];
	refreshContextData?: Record<string, unknown>;
}): Promise<LoaderContext> {
	return {
		collection: collectionName,
		store: this.#store.scopedStore(collectionName),
		meta: this.#store.metaStore(collectionName),
		logger: this.#logger.forkIntegrationLogger(loaderName),
		config: this.#settings.config,
		parseData,
		renderMarkdown: this.#processMarkdown.bind(this),
		generateDigest: await this.#getGenerateDigest(),
		watcher: this.#watcher,
		refreshContextData,
		entryTypes: getEntryConfigByExtMap([
			...this.#settings.contentEntryTypes,
			...this.#settings.dataEntryTypes,
		] as Array<ContentEntryType>),
	};
}

export async function getEntrySlug({
	id,
	collection,
	generatedSlug,
	contentEntryType,
	fileUrl,
	fs,
}: {
	fs: typeof fsMod;
	id: string;
	collection: string;
	generatedSlug: string;
	fileUrl: URL;
	contentEntryType: Pick<ContentEntryType, 'getEntryInfo'>;
}) {
	let contents: string;
	try {
		contents = await fs.promises.readFile(fileUrl, 'utf-8');
	} catch (e) {
		// File contents should exist. Raise unexpected error as "unknown" if not.
		throw new AstroError(AstroErrorData.UnknownContentCollectionError, { cause: e });
	}
	const { slug: frontmatterSlug } = await contentEntryType.getEntryInfo({
		fileUrl,
		contents,
	});
	return parseEntrySlug({ generatedSlug, frontmatterSlug, id, collection });
}

async getMiddleware(): Promise<MiddlewareHandler> {
	if (this.resolvedMiddleware) {
		return this.resolvedMiddleware;
	}
	// The middleware can be undefined when using edge middleware.
	// This is set to undefined by the plugin-ssr.ts
	if (this.middleware) {
		const middlewareInstance = await this.middleware();
		const onRequest = middlewareInstance.onRequest ?? NOOP_MIDDLEWARE_FN;
		const internalMiddlewares = [onRequest];
		if (this.manifest.checkOrigin) {
			// this middleware must be placed at the beginning because it needs to block incoming requests
			internalMiddlewares.unshift(createOriginCheckMiddleware());
		}
		this.resolvedMiddleware = sequence(...internalMiddlewares);
		return this.resolvedMiddleware;
	} else {
		this.resolvedMiddleware = NOOP_MIDDLEWARE_FN;
		return this.resolvedMiddleware;
	}
}

export async function createSettings(
	config: AstroConfig,
	logLevel: AstroInlineConfig['logLevel'],
	cwd?: string,
): Promise<AstroSettings> {
	const tsconfig = await loadTSConfig(cwd);
	const settings = createBaseSettings(config, logLevel);

	let watchFiles = [];
	if (cwd) {
		watchFiles.push(fileURLToPath(new URL('./package.json', pathToFileURL(cwd))));
	}

	if (!tsconfig.error) {
		watchFiles.push(...tsconfig.sources);
		settings.tsConfig = tsconfig.tsconfig;
		settings.tsConfigPath = tsconfig.tsconfigFile;
	}

	settings.watchFiles = watchFiles;

	return settings;
}

getClientAddress(): string {
	const { pipeline, clientAddress } = this;
	const routeData = this.routeData!;

	if (routeData.prerender) {
		throw new AstroError({
			...AstroErrorData.PrerenderClientAddressNotAvailable,
			message: AstroErrorData.PrerenderClientAddressNotAvailable.message(routeData.component),
		});
	}

	if (clientAddress) {
		return clientAddress;
	}

	if (pipeline.adapterName) {
		throw new AstroError({
			...AstroErrorData.ClientAddressNotAvailable,
			message: AstroErrorData.ClientAddressNotAvailable.message(pipeline.adapterName),
		});
	}

	throw new AstroError(AstroErrorData.StaticClientAddressNotAvailable);
}

export function normalizeUrl(url: URL): URL {
	try {
		url.pathname = validateAndDecodePathname(url.pathname);
	} catch (e) {
		// Multi-level encoding (e.g., %2561 → %61) must be rejected, not silently decoded.
		// Let this error propagate so the caller can return a 400 response.
		if (e instanceof MultiLevelEncodingError) {
			throw e;
		}
		// For other decoding failures (truly malformed URLs), fall back gracefully.
		try {
			url.pathname = decodeURI(url.pathname);
		} catch {
			// If even basic decoding fails, return URL as-is
		}
	}
	url.pathname = collapseDuplicateSlashes(url.pathname);
	return url;
}

function appendSpeculationRules(url: string, eagerness: PrefetchOptions['eagerness']) {
	const script = document.createElement('script');
	script.type = 'speculationrules';
	// nosemgrep: javascript.lang.security.audit.unknown-value-with-script-tag.unknown-value-with-script-tag
	// This writes JSON via textContent, not executable JavaScript source.
	script.textContent = JSON.stringify({
		prerender: [
			{
				source: 'list',
				urls: [url],
				eagerness: eagerness,
			},
		],
		// Currently, adding `prefetch` is required to fallback if `prerender` fails.
		// Possibly will be automatic in the future, in which case it can be removed.
		// https://github.com/WICG/nav-speculation/issues/162#issuecomment-1977818473
		prefetch: [
			{
				source: 'list',
				urls: [url],
				eagerness: eagerness,
			},
		],
	});
	document.head.append(script);
}

constructor(
	result: SSRResult,
	props: ComponentProps,
	slots: ComponentSlots,
	factory: AstroComponentFactory,
) {
	this.result = result;
	this.props = props;
	this.factory = factory;
	this.slotValues = {};
	for (const name in slots) {
		// prerender the slots eagerly to make collection entries propagate styles and scripts
		let didRender = false;
		let value = slots[name](result);
		this.slotValues[name] = () => {
			// use prerendered value only once
			if (!didRender) {
				didRender = true;
				return value;
			}
			// render afresh for the advanced use-case where the same slot is rendered multiple times
			return slots[name](result);
		};
	}
}

constructor(htmlParts: TemplateStringsArray, expressions: unknown[]) {
	this.htmlParts = htmlParts;
	this.error = undefined;
	this.expressions = expressions.map((expression) => {
		// Wrap Promise expressions so we can catch errors
		// There can only be 1 error that we rethrow from an Astro component,
		// so this keeps track of whether or not we have already done so.
		if (isPromise(expression)) {
			return Promise.resolve(expression).catch((err) => {
				if (!this.error) {
					this.error = err;
					throw err;
				}
			});
		}
		return expression;
	});
}

acquire(type: QueueNode['type'], content?: string): QueueNode {
	// Pop from the type-specific sub-pool and reuse the object
	const pooledNode = this.popFromTypedPool(type);

	if (pooledNode) {
		if (this.enableStats) {
			this.stats.acquireFromPool = this.stats.acquireFromPool + 1;
		}
		// Reassign value field on the reused object (type discriminant is already correct)
		this.resetNodeContent(pooledNode, type, content);
		return pooledNode;
	}

	// Pool is empty for this type, create new node
	if (this.enableStats) {
		this.stats.acquireNew = this.stats.acquireNew + 1;
	}

	return this.createNode(type, content);
}

async tryRewrite(payload: RewritePayload, request: Request): Promise<TryRewriteResult> {
	if (!this.routesList) {
		throw new Error('Missing manifest data. This is an internal error, please file an issue.');
	}
	const { routeData, pathname, newUrl } = findRouteToRewrite({
		payload,
		request,
		routes: this.routesList?.routes,
		trailingSlash: this.manifest.trailingSlash,
		buildFormat: this.manifest.buildFormat,
		base: this.manifest.base,
		outDir: this.manifest.outDir,
	});

	const componentInstance = await this.getComponentByRoute(routeData);
	return { newUrl, pathname, componentInstance, routeData };
}

static create(
	manifestData: RoutesList,
	{
		loader,
		logger,
		manifest,
		settings,
		getDebugInfo,
	}: Pick<RunnablePipeline, 'loader' | 'logger' | 'manifest' | 'settings' | 'getDebugInfo'>,
) {
	const pipeline = new RunnablePipeline(loader, logger, manifest, settings, getDebugInfo);
	pipeline.routesList = manifestData;
	if (queueRenderingEnabled(manifest.experimentalQueuedRendering)) {
		pipeline.nodePool = newNodePool(manifest.experimentalQueuedRendering!);
		if (manifest.experimentalQueuedRendering!.contentCache) {
			pipeline.htmlStringCache = new HTMLStringCache(1000);
		}
	}
	return pipeline;
}

export function recordServerError(
	loader: ModuleLoader,
	manifest: SSRManifest,
	logger: AstroLogger,
	err: Error,
) {
	// This could be a runtime error from Vite's SSR module, so try to fix it here
	try {
		loader.fixStacktrace(err);
	} catch {}

	// This is our last line of defense regarding errors where we still might have some information about the request
	// Our error should already be complete, but let's try to add a bit more through some guesswork
	const errorWithMetadata = collectErrorMetadata(err, manifest.rootDir);

	logger.error(null, formatErrorMessage(errorWithMetadata, logger.level() === 'debug'));

	return {
		errorWithMetadata,
	};
}

export function normalizeFilename(filename: string, root: URL) {
	if (filename.startsWith('/@fs')) {
		filename = filename.slice('/@fs'.length);
	} else if (filename.startsWith('.')) {
		// Handle relative paths (e.g. ./src/components/Foo.astro) by resolving against root.
		// This can occur on certain environments (e.g. Windows + newer Node.js) when a component
		// is imported via a TypeScript path alias and Vite produces a relative virtual module ID.
		const url = new URL(filename, root);
		filename = viteID(url);
	} else if (filename.startsWith('/') && !isPathInRoot(filename, fileURLToPath(root))) {
		const url = new URL('.' + filename, root);
		filename = viteID(url);
	}
	return removeLeadingForwardSlashWindows(filename);
}

export async function cf(
	state: FetchState,
	env: Env,
	ctx: ExecutionContext,
): Promise<Response | undefined> {
	ensureInitialized();
	injectSessionBinding(app!.manifest, env);

	const staticAsset = matchStaticAsset(app!.manifest, state.request.url, env);
	if (staticAsset) return staticAsset;

	if (!state.routeData) {
		const asset = await fallbackToAssets(state.request.url, env);
		if (asset) return asset;
	}

	Object.assign(state.locals, createLocals(ctx));
	state.clientAddress = getClientAddress(state.request);
	state.renderOptions.waitUntil = ctx.waitUntil.bind(ctx);
	state.renderOptions.prerenderedErrorPageFetch = createErrorPageFetch(env);

	return undefined;
}

export function createContentComponent(
	Renderer: AstroInstance['default'],
	stringifiedAst: string,
	userConfig: AstroMarkdocConfig,
	options: MarkdocIntegrationOptions | undefined,
	tagComponentMap: Record<string, AstroInstance['default']>,
	nodeComponentMap: Record<NodeType, AstroInstance['default']>,
) {
	return createComponent({
		async factory(result: any, props: Record<string, any>) {
			const withVariables = mergeConfig(userConfig, { variables: props });
			const config = resolveComponentImports(
				await setupConfig(withVariables, options),
				tagComponentMap,
				nodeComponentMap,
			);

			return renderComponent(result, Renderer.name, Renderer, { stringifiedAst, config }, {});
		},
		propagation: 'self',
	} as any);
}

export function createShikiHighlighter(
	options?: CreateShikiHighlighterOptions,
): Promise<ShikiHighlighter> {
	// Although this function returns a promise, its body runs synchronously so
	// that the cache lookup happens immediately. Without this, calling
	// `Promise.all([createShikiHighlighter(), createShikiHighlighter()])` would
	// bypass the cache and create duplicate highlighters.

	const key: string = getCacheKey(options);
	let highlighterPromise = cachedHighlighters.get(key);
	if (!highlighterPromise) {
		highlighterPromise = createShikiHighlighterInternal(options);
		cachedHighlighters.set(key, highlighterPromise);
	}
	return ensureLanguagesLoaded(highlighterPromise, options?.langs);
}

function rewriteAstroComponentCompletion(completion: CompletionItem) {
	completion.label = stripAstroComponentSuffix(String(completion.label));
	completion.filterText = completion.filterText
		? stripAstroComponentSuffix(completion.filterText)
		: completion.filterText;
	completion.insertText = completion.insertText
		? stripAstroComponentSuffix(completion.insertText)
		: completion.insertText;

	if (completion.textEdit && 'newText' in completion.textEdit) {
		completion.textEdit.newText = stripAstroComponentSuffix(completion.textEdit.newText);
	}

	if (completion.additionalTextEdits) {
		completion.additionalTextEdits = completion.additionalTextEdits.map((edit) => ({
			...edit,
			newText: rewriteAstroImportText(edit.newText),
		}));
	}
}

export async function main() {
	// NOTE: In the v7.x version of npm, the default behavior of `npm init` was changed
	// to no longer require `--` to pass args and instead pass `--` directly to us. This
	// broke our arg parser, since `--` is a special kind of flag. Filtering for `--` here
	// fixes the issue so that create-astro now works on all npm versions.
	const cleanArgv = process.argv.slice(2).filter((arg) => arg !== '--');
	const ctx = await getContext(cleanArgv);
	if (ctx.help) {
		help();
		return;
	}

	const steps = [verify, install];

	for (const step of steps) {
		await step(ctx);
	}
	process.exit(0);
}

constructor({
	config,
	astroVersionProvider,
	packageManager,
	operatingSystemProvider,
	nodeVersionProvider,
}: {
	config: Pick<AstroConfig, 'output' | 'adapter' | 'integrations'>;
	astroVersionProvider: AstroVersionProvider;
	packageManager: PackageManager;
	operatingSystemProvider: OperatingSystemProvider;
	nodeVersionProvider: NodeVersionProvider;
}) {
	this.#config = config;
	this.#astroVersionProvider = astroVersionProvider;
	this.#packageManager = packageManager;
	this.#operatingSystemProvider = operatingSystemProvider;
	this.#nodeVersionProvider = nodeVersionProvider;
}

public addServerRenderer(options: AddServerRenderer): void {
	const { renderer } = options;
	if (!renderer.check || !renderer.renderToStaticMarkup) {
		throw new Error(
			"The renderer you passed isn't valid. A renderer is usually an object that exposes the `check` and `renderToStaticMarkup` functions.\n" +
				"Usually, the renderer is exported by a /server.js entrypoint e.g. `import renderer from '@astrojs/react/server.js'`",
		);
	}
	if (isNamedRenderer(renderer)) {
		this.#pipeline.manifest.renderers.push({
			name: renderer.name,
			ssr: renderer,
		});
	} else if ('name' in options) {
		this.#pipeline.manifest.renderers.push({
			name: options.name,
			ssr: renderer,
		});
	} else {
		throw new Error(
			'The renderer name must be provided when adding a server renderer that is not a named renderer.',
		);
	}
}

function asyncIterableToBodyProps(
	iterable: AsyncIterable<any>,
	bodySizeLimit?: number,
): RequestInit {
	const source = bodySizeLimit != null ? limitAsyncIterable(iterable, bodySizeLimit) : iterable;
	return {
		// Node uses undici for the Request implementation. Undici accepts
		// a non-standard async iterable for the body.
		// @ts-expect-error
		body: source,
		// The duplex property is required when using a ReadableStream or async
		// iterable for the body. The type definitions do not include the duplex
		// property because they are not up-to-date.
		duplex: 'half',
	};
}

export function toIntegrationResolvedRoute(
	route: RouteData,
	trailingSlash: AstroConfig['trailingSlash'],
): IntegrationResolvedRoute {
	return {
		isPrerendered: route.prerender,
		entrypoint: route.component,
		pattern: route.route,
		params: route.params,
		origin: route.origin,
		generate: getRouteGenerator(route.segments, trailingSlash),
		patternRegex: route.pattern,
		segments: route.segments,
		type: route.type,
		pathname: route.pathname,
		redirect: route.redirect,
		redirectRoute: route.redirectRoute
			? toIntegrationResolvedRoute(route.redirectRoute, trailingSlash)
			: undefined,
		fallbackRoutes: route.fallbackRoutes.map((fallbackRoute) =>
			toIntegrationResolvedRoute(fallbackRoute, trailingSlash),
		),
	};
}

(value: any) => {
	// If value is already marked as an HTML string, there is nothing to do.
	if (isHTMLString(value)) {
		return value;
	}
	// Cast to `HTMLString` to mark the string as valid HTML. Any HTML escaping
	// and sanitization should have already happened to the `value` argument.
	// NOTE: `unknown as string` is necessary for TypeScript to treat this as `string`
	if (typeof value === 'string') {
		return new HTMLString(value) as unknown as string;
	}
	// Return all other values (`number`, `null`, `undefined`) as-is.
	// The compiler will recursively stringify these correctly at a later stage.
	return value;
}

export function createMdxProcessor(
	mdxOptions: ResolvedMdxOptions,
	extraOptions: MdxProcessorExtraOptions,
) {
	return createProcessor({
		remarkPlugins: getRemarkPlugins(mdxOptions),
		rehypePlugins: getRehypePlugins(mdxOptions),
		recmaPlugins: mdxOptions.recmaPlugins,
		remarkRehypeOptions: mdxOptions.remarkRehype,
		jsxImportSource: 'astro',
		// Note: disable `.md` (and other alternative extensions for markdown files like `.markdown`) support
		format: 'mdx',
		mdExtensions: [],
		elementAttributeNameCase: 'html',
		SourceMapGenerator: extraOptions.sourcemap ? SourceMapGenerator : undefined,
	});
}

function addTranslationsForLocale(
	locale: string | undefined,
	config: StarlightConfig,
	useTranslations: UseTranslations
) {
	const lang = localeToLang(config, locale);
	const t = useTranslations(lang);
	const translationKeys = [
		'expressiveCode.copyButtonCopied',
		'expressiveCode.copyButtonTooltip',
		'expressiveCode.terminalWindowFallbackTitle',
	] as const;
	translationKeys.forEach((key) => {
		const translation = t.exists(key) ? t(key) : undefined;
		if (!translation) return;
		const ecId = key.replace(/^expressiveCode\./, '');
		pluginFramesTexts.overrideTexts(lang, { [ecId]: translation });
	});
}
